function usePayrollData(month, employeeId, isAdmin) {
  return useQuery({
    queryKey: ["accounting_payroll", month],
    enabled: !!employeeId && isAdmin && !!month,
    queryFn: async () => {
      const qs = new URLSearchParams({
        month: String(month)
      });
      const res = await adminFetch(`/api/accounting/payroll?${qs.toString()}`);
      const data = await res.json().catch(() => ({}));
      if (!res.ok) {
        throw new Error(data?.error || `When fetching /api/accounting/payroll, the response was [${res.status}] ${res.statusText}`);
      }
      return data;
    }
  });
}

function usePayrollRebuild() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async ({
      month
    }) => {
      const res = await adminFetch("/api/accounting/payroll", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          month: String(month)
        })
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok) {
        throw new Error(data?.error || `When fetching /api/accounting/payroll, the response was [${res.status}] ${res.statusText}`);
      }
      return data;
    },
    onSuccess: async (_data, vars) => {
      await queryClient.invalidateQueries({
        queryKey: ["accounting_payroll", String(vars.month)]
      });
      toast.success("تم تحديث مسير الرواتب");
    },
    onError: error => {
      console.error(error);
      toast.error(`فشل تحديث المسير: ${error.message}`);
    }
  });
}
