const ADMIN_LOGIN_PATH = "/admin/login";
function useEmployeesAuth() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  useEffect(() => {
    const auth = localStorage.getItem("adminAuth");
    const token = localStorage.getItem(ADMIN_TOKEN_KEY);
    if (!auth || !token) {
      window.location.href = ADMIN_LOGIN_PATH;
      return;
    }

    // Guard: only admins with can_manage_employees can access /admin/employees
    try {
      const raw = localStorage.getItem("adminUser");
      const u = raw ? JSON.parse(raw) : null;
      const allowed = !!u?.can_manage_employees;
      if (!allowed) {
        window.location.href = "/admin";
        return;
      }
    } catch {
      window.location.href = "/admin";
      return;
    }
    setIsAuthenticated(true);
  }, []);
  const handleLogout = () => {
    localStorage.removeItem("adminAuth");
    localStorage.removeItem("adminUser");
    localStorage.removeItem("adminMode");
    localStorage.removeItem("workspaceUser");
    localStorage.removeItem(ADMIN_TOKEN_KEY);
    window.location.href = ADMIN_LOGIN_PATH;
  };
  return {
    isAuthenticated,
    handleLogout
  };
}

function useEmployeesData(isAuthenticated) {
  const employeesQuery = useQuery({
    queryKey: ["employees"],
    queryFn: async () => {
      const response = await adminFetch("/api/employees");
      if (!response.ok) {
        throw new Error(`When fetching /api/employees, the response was [${response.status}] ${response.statusText}`);
      }
      return response.json();
    },
    enabled: isAuthenticated
  });
  const branchesQuery = useQuery({
    queryKey: ["branches"],
    queryFn: async () => {
      const response = await adminFetch("/api/branches");
      if (!response.ok) {
        throw new Error(`When fetching /api/branches, the response was [${response.status}] ${response.statusText}`);
      }
      return response.json();
    },
    enabled: isAuthenticated
  });
  return {
    employees: employeesQuery.data,
    isLoadingEmployees: employeesQuery.isLoading,
    employeesError: employeesQuery.error,
    branches: branchesQuery.data,
    branchesError: branchesQuery.error
  };
}

function useEmployeeMutations() {
  const queryClient = useQueryClient();
  const createMutation = useMutation({
    mutationFn: async data => {
      const response = await adminFetch("/api/employees", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(data)
      });
      const result = await response.json();
      if (!response.ok) {
        throw new Error(result.details || result.error || "Failed to create employee");
      }
      return result;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["employees"]
      });
      toast.success("تم إضافة الموظف بنجاح");
    },
    onError: error => {
      console.error("Create employee error:", error);
      toast.error(`فشل إضافة الموظف: ${error.message}`);
    }
  });
  const updateMutation = useMutation({
    mutationFn: async ({
      id,
      data
    }) => {
      const response = await adminFetch(`/api/employees/${id}`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(data)
      });
      const result = await response.json();
      if (!response.ok) {
        throw new Error(result.error || result.details || "Failed to update employee");
      }
      return result;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["employees"]
      });
      toast.success("تم تحديث الموظف بنجاح");
    },
    onError: error => {
      console.error("Update employee error:", error);
      toast.error(error.message || "فشل تحديث الموظف");
    }
  });
  const deleteMutation = useMutation({
    mutationFn: async id => {
      const response = await adminFetch(`/api/employees/${id}`, {
        method: "DELETE"
      });
      if (!response.ok) throw new Error("Failed to delete employee");
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["employees"]
      });
      toast.success("تم حذف الموظف بنجاح");
    },
    onError: error => {
      toast.error("فشل حذف الموظف");
      console.error(error);
    }
  });
  return {
    createMutation,
    updateMutation,
    deleteMutation
  };
}

